import { useState, useEffect } from 'react';
import { EventResult } from '@/types/event.types';
import { getSelectedEventContext, getSelectedEventId } from '@/utils/eventContext';

/**
 * Custom hook to get the selected event context from localStorage
 * @returns object with selectedEvent, selectedEventId, and refresh function
 */
export const useSelectedEventContext = () => {
    const [selectedEvent, setSelectedEvent] = useState<EventResult | null>(null);
    const [selectedEventId, setSelectedEventId] = useState<string | null>(null);

    const refreshEventContext = () => {
        const event = getSelectedEventContext();
        const eventId = getSelectedEventId();
        setSelectedEvent(event);
        setSelectedEventId(eventId);
    };

    useEffect(() => {
        // Load on mount
        refreshEventContext();

        // Listen for localStorage changes from other tabs/windows
        const handleStorageChange = (e: StorageEvent) => {
            if (e.key === 'selectedEventContext') {
                refreshEventContext();
            }
        };

        window.addEventListener('storage', handleStorageChange);
        return () => window.removeEventListener('storage', handleStorageChange);
    }, []);

    return {
        selectedEvent,
        selectedEventId,
        refreshEventContext,
        hasSelectedEvent: selectedEvent !== null
    };
};